sub extract_pdf_data {
    my ($file_path) = @_;

    # Load the PDF file
    my $pdf = PDF::API2->open($file_path);

    # Extract text from the PDF
    my $extracted_text = PDF::Text::Simple->extract($pdf);

    # Initialize variables to store extracted data
    my ($date, $author, $tables);

    # Process the extracted text to find the required information
    foreach my $line (@$extracted_text) {
        if ($line =~ /Date:\s*(\d{1,2}\/\d{1,2}\/\d{4})/) {
            $date = $1;
        }
        elsif ($line =~ /Author:\s*(\w+)/) {
            $author = $1;
        }
        # For tables, we assume they are in a specific format (e.g., tab-separated values)
        elsif ($line =~ /\d+\s+\d+\s+\d+/) {
            push @$tables, [split /\s+/ => $line];
        }
    }

    # Save extracted data to a CSV file
    my $csv = Text::CSV->new({ binary => 1 });
    open my $fh, '>', 'extracted_data.csv' or die "Can't open 'extracted_data.csv' $!";
    $csv->print($fh, [$date, $author, map { $_->[0] } @$tables]);
    close $fh;

    return ($date, $author, $tables);
}

